+import type { Album, GooglePhotosClient, Photo } from './types';
+
+type AlbumListResponse = { albums?: Array<{ id: string; title: string; productUrl?: string; mediaItemsCount?: string }>; nextPageToken?: string };
+type MediaListResponse = { mediaItems?: Array<{ id: string; baseUrl: string; filename: string; mimeType?: string; productUrl?: string; mediaMetadata?: { creationTime?: string } }>; nextPageToken?: string };
+type SearchAlbumResponse = { mediaItems?: Array<{ id: string }>; nextPageToken?: string };
+
+async function googleFetch<T>(token: string, path: string, init?: RequestInit): Promise<T> {
+  const response = await fetch(`https://photoslibrary.googleapis.com/v1${path}`, {
+    ...init,
+    headers: {
+      Authorization: `Bearer ${token}`,
+      'Content-Type': 'application/json',
+      ...(init?.headers ?? {}),
+    },
+  });
+
+  if (!response.ok) {
+    const body = await response.text();
+    throw new Error(body || `Google Photos request failed with ${response.status}.`);
+  }
+
+  if (response.status === 204) {
+    return undefined as T;
+  }
+
+  return (await response.json()) as T;
+}
+
+async function collectPaginated<T>(
+  loadPage: (pageToken?: string) => Promise<{ items: T[]; nextPageToken?: string }>,
+): Promise<T[]> {
+  const results: T[] = [];
+  let pageToken: string | undefined;
+
+  do {
+    const page = await loadPage(pageToken);
+    results.push(...page.items);
+    pageToken = page.nextPageToken;
+  } while (pageToken);
+
+  return results;
+}
+
+export function createGooglePhotosClient(token: string): GooglePhotosClient {
+  return {
+    async listAlbums() {
+      return collectPaginated<Album>(async (pageToken) => {
+        const params = new URLSearchParams({ pageSize: '50' });
+        if (pageToken) {
+          params.set('pageToken', pageToken);
+        }
+
+        const response = await googleFetch<AlbumListResponse>(token, `/albums?${params.toString()}`);
+        return {
+          items:
+            response.albums?.map((album) => ({
+              id: album.id,
+              title: album.title,
+              productUrl: album.productUrl,
+              mediaItemsCount: album.mediaItemsCount,
+            })) ?? [],
+          nextPageToken: response.nextPageToken,
+        };
+      });
+    },
+
+    async listPhotos() {
+      const photos = await collectPaginated<Photo>(async (pageToken) => {
+        const params = new URLSearchParams({ pageSize: '100' });
+        if (pageToken) {
+          params.set('pageToken', pageToken);
+        }
+
+        const response = await googleFetch<MediaListResponse>(token, `/mediaItems?${params.toString()}`);
+        return {
+          items:
+            response.mediaItems?.map((photo) => ({
+              id: photo.id,
+              baseUrl: photo.baseUrl,
+              filename: photo.filename,
+              mimeType: photo.mimeType,
+              productUrl: photo.productUrl,
+              createdAt: photo.mediaMetadata?.creationTime ?? new Date(0).toISOString(),
+            })) ?? [],
+          nextPageToken: response.nextPageToken,
+        };
+      });
+
+      return photos.sort((left, right) => right.createdAt.localeCompare(left.createdAt));
+    },
+
+    async createAlbum(title) {
+      const response = await googleFetch<{ id: string; title: string; productUrl?: string }>(token, '/albums', {
+        method: 'POST',
+        body: JSON.stringify({ album: { title } }),
+      });
+
+      return {
+        id: response.id,
+        title: response.title,
+        productUrl: response.productUrl,
+      };
+    },
+
+    async renameAlbum(albumId, title) {
+      const params = new URLSearchParams({ updateMask: 'title' });
+      const response = await googleFetch<{ id: string; title: string; productUrl?: string }>(
+        token,
+        `/albums/${albumId}?${params.toString()}`,
+        {
+          method: 'PATCH',
+          body: JSON.stringify({ title }),
+        },
+      );
+
+      return {
+        id: response.id,
+        title: response.title,
+        productUrl: response.productUrl,
+      };
+    },
+
+    async addPhotoToAlbum(albumId, photoId) {
+      await googleFetch<void>(token, `/albums/${albumId}:batchAddMediaItems`, {
+        method: 'POST',
+        body: JSON.stringify({ mediaItemIds: [photoId] }),
+      });
+    },
+
+    async removePhotoFromAlbum(albumId, photoId) {
+      await googleFetch<void>(token, `/albums/${albumId}:batchRemoveMediaItems`, {
+        method: 'POST',
+        body: JSON.stringify({ mediaItemIds: [photoId] }),
+      });
+    },
+
+    async isPhotoInAlbum(albumId, photoId) {
+      let pageToken: string | undefined;
+
+      do {
+        const response = await googleFetch<SearchAlbumResponse>(token, '/mediaItems:search', {
+          method: 'POST',
+          body: JSON.stringify({
+            albumId,
+            pageSize: 100,
+            pageToken,
+          }),
+        });
+
+        if (response.mediaItems?.some((photo) => photo.id === photoId)) {
+          return true;
+        }
+
+        pageToken = response.nextPageToken;
+      } while (pageToken);
+
+      return false;
+    },
+  };
+}
