import { useEffect, useMemo, useState } from 'react';
import { assignAlbumShortcuts } from './lib/albumShortcuts';
import { createGoogleAuthAdapter, type AuthAdapter } from './lib/googleAuth';
import { createGooglePhotosClient } from './lib/googlePhotos';
import type { Album, GooglePhotosClient, Photo } from './lib/types';

type AppProps = {
  authAdapter?: AuthAdapter;
  clientFactory?: (token: string) => GooglePhotosClient;
};

type LoadState = 'signed-out' | 'signing-in' | 'loading' | 'ready' | 'error';

function sortAlbums(albums: Album[]): Album[] {
  return [...albums].sort((left, right) => left.title.localeCompare(right.title));
}

function formatDate(value: string): string {
  return new Intl.DateTimeFormat(undefined, {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(new Date(value));
}

export default function App({
  authAdapter = createGoogleAuthAdapter(import.meta.env.VITE_GOOGLE_CLIENT_ID),
  clientFactory = createGooglePhotosClient,
}: AppProps) {
  const [status, setStatus] = useState<LoadState>('signed-out');
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [client, setClient] = useState<GooglePhotosClient | null>(null);
  const [albums, setAlbums] = useState<Album[]>([]);
  const [photos, setPhotos] = useState<Photo[]>([]);
  const [photoIndex, setPhotoIndex] = useState(0);
  const [memberships, setMemberships] = useState<Set<string>>(new Set());
  const [newAlbumTitle, setNewAlbumTitle] = useState('');
  const [renamingAlbumId, setRenamingAlbumId] = useState<string | null>(null);
  const [renameDraft, setRenameDraft] = useState('');

  const currentPhoto = photos[photoIndex] ?? null;
  const shortcuts = useMemo(() => assignAlbumShortcuts(albums), [albums]);

  async function refreshMemberships(nextClient: GooglePhotosClient, nextAlbums: Album[], photo: Photo | null) {
    if (!photo) {
      setMemberships(new Set());
      return;
    }

    const membershipEntries = await Promise.all(
      nextAlbums.map(async (album) => [album.id, await nextClient.isPhotoInAlbum(album.id, photo.id)] as const),
    );

    setMemberships(
      new Set(membershipEntries.filter(([, isMember]) => isMember).map(([albumId]) => albumId)),
    );
  }

  async function loadLibrary(nextClient: GooglePhotosClient) {
    setStatus('loading');
    setErrorMessage(null);

    try {
      const [loadedAlbums, loadedPhotos] = await Promise.all([
        nextClient.listAlbums(),
        nextClient.listPhotos(),
      ]);
      const sortedAlbums = sortAlbums(loadedAlbums);
      setAlbums(sortedAlbums);
      setPhotos(loadedPhotos);
      setPhotoIndex(0);
      await refreshMemberships(nextClient, sortedAlbums, loadedPhotos[0] ?? null);
      setStatus('ready');
    } catch (error) {
      setStatus('error');
      setErrorMessage(error instanceof Error ? error.message : 'Unable to load Google Photos data.');
    }
  }

  async function handleSignIn() {
    setStatus('signing-in');
    setErrorMessage(null);

    try {
      const token = await authAdapter.signIn();
      const nextClient = clientFactory(token);
      setClient(nextClient);
      await loadLibrary(nextClient);
    } catch (error) {
      setStatus('error');
      setErrorMessage(error instanceof Error ? error.message : 'Unable to sign in.');
    }
  }

  async function handleCreateAlbum(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (!client) {
      return;
    }

    const title = newAlbumTitle.trim();
    if (!title) {
      return;
    }

    const createdAlbum = await client.createAlbum(title);
    const nextAlbums = sortAlbums([...albums, createdAlbum]);
    setAlbums(nextAlbums);
    setNewAlbumTitle('');
    await refreshMemberships(client, nextAlbums, currentPhoto);
  }

  async function handleRenameAlbum(albumId: string) {
    if (!client) {
      return;
    }

    const title = renameDraft.trim();
    if (!title) {
      return;
    }

    const renamedAlbum = await client.renameAlbum(albumId, title);
    const nextAlbums = sortAlbums(albums.map((album) => (album.id === albumId ? renamedAlbum : album)));
    setAlbums(nextAlbums);
    setRenamingAlbumId(null);
    setRenameDraft('');
    await refreshMemberships(client, nextAlbums, currentPhoto);
  }

  async function toggleAlbum(albumId: string) {
    if (!client || !currentPhoto) {
      return;
    }

    const isMember = memberships.has(albumId);
    if (isMember) {
      await client.removePhotoFromAlbum(albumId, currentPhoto.id);
    } else {
      await client.addPhotoToAlbum(albumId, currentPhoto.id);
    }

    setMemberships((previous) => {
      const next = new Set(previous);
      if (isMember) {
        next.delete(albumId);
      } else {
        next.add(albumId);
      }
      return next;
    });
  }

  useEffect(() => {
    if (!client || !currentPhoto || status !== 'ready') {
      return;
    }

    void refreshMemberships(client, albums, currentPhoto);
  }, [albums, client, currentPhoto, status]);

  useEffect(() => {
    if (status !== 'ready') {
      return;
    }

    const handler = (event: KeyboardEvent) => {
      if (event.metaKey || event.ctrlKey || event.altKey) {
        return;
      }

      const target = event.target;
      if (target instanceof HTMLElement) {
        const tag = target.tagName.toLowerCase();
        if (tag === 'input' || tag === 'textarea' || target.isContentEditable) {
          return;
        }
      }

      if (event.key === 'ArrowLeft') {
        setPhotoIndex((index) => Math.max(index - 1, 0));
        return;
      }

      if (event.key === 'ArrowRight') {
        setPhotoIndex((index) => Math.min(index + 1, photos.length - 1));
        return;
      }

      const normalizedKey = event.key.toUpperCase();
      const album = albums.find((item) => shortcuts.get(item.id) === normalizedKey);
      if (album) {
        void toggleAlbum(album.id);
      }
    };

    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [albums, photos.length, shortcuts, status, currentPhoto, memberships]);

  return (
    <div className="app-shell">
      <header className="topbar">
        <div>
          <p className="eyebrow">Google Photos Keyboard Manager</p>
          <h1>EZGPhotos</h1>
        </div>
        <button className="primary-button" onClick={handleSignIn} disabled={status === 'signing-in' || status === 'loading'}>
          {status === 'signed-out' || status === 'error' ? 'Login with Google' : 'Reload library'}
        </button>
      </header>

      <section className="notice">
        <p>
          Configure <code>VITE_GOOGLE_CLIENT_ID</code> to use the live Google sign-in flow. Google’s current Photos Library API behavior is scoped by the permissions your app has been granted.
        </p>
      </section>

      {errorMessage ? <p className="error-banner">{errorMessage}</p> : null}

      <main className="workspace">
        <aside className="sidebar">
          <div className="panel-header">
            <h2>Albums</h2>
            <span>{albums.length}</span>
          </div>

          <form className="album-form" onSubmit={handleCreateAlbum}>
            <input
              aria-label="New album title"
              placeholder="Create album"
              value={newAlbumTitle}
              onChange={(event) => setNewAlbumTitle(event.target.value)}
              disabled={!client}
            />
            <button type="submit" disabled={!client || !newAlbumTitle.trim()}>
              Add
            </button>
          </form>

          <ul className="album-list" aria-label="Albums">
            {albums.map((album) => {
              const isActive = memberships.has(album.id);
              const isRenaming = renamingAlbumId === album.id;
              return (
                <li key={album.id} className={`album-row${isActive ? ' active' : ''}`}>
                  <button
                    type="button"
                    className="shortcut-pill"
                    onClick={() => void toggleAlbum(album.id)}
                    disabled={!currentPhoto}
                    aria-label={`Toggle ${album.title}`}
                  >
                    {shortcuts.get(album.id)}
                  </button>
                  <div className="album-meta">
                    {isRenaming ? (
                      <form
                        className="rename-form"
                        onSubmit={(event) => {
                          event.preventDefault();
                          void handleRenameAlbum(album.id);
                        }}
                      >
                        <input
                          aria-label={`Rename ${album.title}`}
                          value={renameDraft}
                          onChange={(event) => setRenameDraft(event.target.value)}
                        />
                        <button type="submit">Save</button>
                      </form>
                    ) : (
                      <>
                        <span className="album-title">{album.title}</span>
                        <button
                          type="button"
                          className="ghost-button"
                          onClick={() => {
                            setRenamingAlbumId(album.id);
                            setRenameDraft(album.title);
                          }}
                        >
                          Rename
                        </button>
                      </>
                    )}
                  </div>
                  <span className={`status-mark${isActive ? ' on' : ''}`} aria-label={isActive ? `${album.title} contains current photo` : `${album.title} does not contain current photo`}>
                    {isActive ? '✓' : ''}
                  </span>
                </li>
              );
            })}
          </ul>
        </aside>

        <section className="viewer">
          <div className="panel-header">
            <h2>Target photo</h2>
            <span>{photos.length ? `${photoIndex + 1} / ${photos.length}` : '0 / 0'}</span>
          </div>

          {status === 'loading' || status === 'signing-in' ? <p className="empty-state">Loading Google Photos…</p> : null}

          {status === 'signed-out' ? (
            <p className="empty-state">Sign in to load your albums and photos.</p>
          ) : null}

          {status === 'ready' && currentPhoto ? (
            <>
              <div className="photo-card">
                <button
                  className="nav-button"
                  onClick={() => setPhotoIndex((index) => Math.max(index - 1, 0))}
                  disabled={photoIndex === 0}
                  aria-label="Previous photo"
                >
                  ←
                </button>

                <figure>
                  <img src={`${currentPhoto.baseUrl}=w1200-h900`} alt={currentPhoto.filename} />
                  <figcaption>
                    <strong>{currentPhoto.filename}</strong>
                    <span>{formatDate(currentPhoto.createdAt)}</span>
                  </figcaption>
                </figure>

                <button
                  className="nav-button"
                  onClick={() => setPhotoIndex((index) => Math.min(index + 1, photos.length - 1))}
                  disabled={photoIndex === photos.length - 1}
                  aria-label="Next photo"
                >
                  →
                </button>
              </div>
              <p className="hint">Use the keyboard: left/right arrows move through photos, album letters toggle membership.</p>
            </>
          ) : null}

          {status === 'ready' && !currentPhoto ? <p className="empty-state">No photos available for this account.</p> : null}
        </section>
      </main>
    </div>
  );
}

