import { fireEvent, render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import App from './App';
import { createMockClient, createAuthAdapter } from './test/mocks';
import type { Album, Photo } from './lib/types';

const albums: Album[] = [
  { id: 'family', title: 'Family' },
  { id: 'office', title: 'Office' },
  { id: 'baby', title: 'Baby' },
  { id: 'baby-shower', title: 'Baby Shower' },
];

const photos: Photo[] = [
  {
    id: 'photo-older',
    baseUrl: 'https://example.com/older',
    filename: 'older.jpg',
    createdAt: '2024-01-01T10:00:00.000Z',
  },
  {
    id: 'photo-newer',
    baseUrl: 'https://example.com/newer',
    filename: 'newer.jpg',
    createdAt: '2024-02-01T10:00:00.000Z',
  },
];

function renderApp() {
  const client = createMockClient({
    albums,
    photos,
    memberships: {
      'photo-newer': ['family'],
      'photo-older': ['office'],
    },
  });

  return render(
    <App
      authAdapter={createAuthAdapter()}
      clientFactory={() => client}
    />,
  );
}

async function login() {
  await userEvent.click(screen.getByRole('button', { name: /login with google/i }));
  await screen.findByText('newer.jpg');
}

describe('EZGPhotos app', () => {
  it('loads the most recent photo first and supports arrow navigation', async () => {
    renderApp();
    await login();

    expect(screen.getByText('newer.jpg')).toBeInTheDocument();

    fireEvent.keyDown(window, { key: 'ArrowRight' });
    await screen.findByText('older.jpg');

    fireEvent.keyDown(window, { key: 'ArrowLeft' });
    await screen.findByText('newer.jpg');
  });

  it('creates and renames albums', async () => {
    renderApp();
    await login();

