import { fireEvent, render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import App from './App';
import { createMockClient, createAuthAdapter } from './test/mocks';
import type { Album, Photo } from './lib/types';

const albums: Album[] = [
  { id: 'family', title: 'Family' },
  { id: 'office', title: 'Office' },
  { id: 'baby', title: 'Baby' },
  { id: 'baby-shower', title: 'Baby Shower' },
];

const photos: Photo[] = [
  {
    id: 'photo-older',
    baseUrl: 'https://example.com/older',
    filename: 'older.jpg',
    createdAt: '2024-01-01T10:00:00.000Z',
  },
  {
    id: 'photo-newer',
    baseUrl: 'https://example.com/newer',
    filename: 'newer.jpg',
    createdAt: '2024-02-01T10:00:00.000Z',
  },
];

function renderApp() {
  const client = createMockClient({
    albums,
    photos,
    memberships: {
      'photo-newer': ['family'],
      'photo-older': ['office'],
    },
  });

  return render(
    <App
      authAdapter={createAuthAdapter()}
      clientFactory={() => client}
    />,
  );
}

async function login() {
  await userEvent.click(screen.getByRole('button', { name: /login with google/i }));
  await screen.findByText('newer.jpg');
}

describe('EZGPhotos app', () => {
  it('loads the most recent photo first and supports arrow navigation', async () => {
    renderApp();
    await login();

    expect(screen.getByText('newer.jpg')).toBeInTheDocument();

    fireEvent.keyDown(window, { key: 'ArrowRight' });
    await screen.findByText('older.jpg');

    fireEvent.keyDown(window, { key: 'ArrowLeft' });
    await screen.findByText('newer.jpg');
  });

  it('creates and renames albums', async () => {
    renderApp();
    await login();

    await userEvent.type(screen.getByLabelText(/new album title/i), 'London Trip');
    await userEvent.click(screen.getByRole('button', { name: /^add$/i }));
    await screen.findByText('London Trip');

    await userEvent.click(screen.getAllByRole('button', { name: /rename/i }).at(-1)!);
    const renameInput = screen.getByLabelText(/rename london trip/i);
    await userEvent.clear(renameInput);
    await userEvent.type(renameInput, 'Love');
    await userEvent.click(screen.getByRole('button', { name: /save/i }));

    await screen.findByText('Love');
  });

  it('shows shortcut letters and toggles the current photo in albums from the keyboard', async () => {
    renderApp();
    await login();

    expect(screen.getByRole('button', { name: /toggle family/i })).toHaveTextContent('F');
    expect(screen.getByRole('button', { name: /toggle office/i })).toHaveTextContent('F');
    expect(screen.getByRole('button', { name: /toggle baby/i })).toHaveTextContent('B');
    expect(screen.getByRole('button', { name: /toggle baby shower/i })).toHaveTextContent('S');

    expect(screen.getByLabelText(/family contains current photo/i)).toHaveTextContent('✓');
    expect(screen.getByLabelText(/office does not contain current photo/i)).toHaveTextContent('');

    fireEvent.keyDown(window, { key: 'O' });
    await waitFor(() => {
      expect(screen.getByLabelText(/office contains current photo/i)).toHaveTextContent('✓');
    });

    fireEvent.keyDown(window, { key: 'F' });
    await waitFor(() => {
      expect(screen.getByLabelText(/family does not contain current photo/i)).toHaveTextContent('');
    });
  });

  it('supports multiple album memberships for a photo', async () => {
    renderApp();
    await login();

    fireEvent.keyDown(window, { key: 'B' });
    fireEvent.keyDown(window, { key: 'S' });

    await waitFor(() => {
      expect(screen.getByLabelText(/baby contains current photo/i)).toHaveTextContent('✓');
      expect(screen.getByLabelText(/baby shower contains current photo/i)).toHaveTextContent('✓');
      expect(screen.getByLabelText(/family contains current photo/i)).toHaveTextContent('✓');
    });
  });
});

