import type { Album, GooglePhotosClient, Photo } from '../lib/types';

export function createAuthAdapter() {
  return {
    signIn: async () => 'test-token',
  };
}

export function createMockClient(seed?: {
  albums?: Album[];
  photos?: Photo[];
  memberships?: Record<string, string[]>;
}): GooglePhotosClient {
  let albumCounter = seed?.albums?.length ?? 0;
  const albums = [...(seed?.albums ?? [])];
  const photos = [...(seed?.photos ?? [])];
  const memberships = new Map<string, Set<string>>();

  for (const photo of photos) {
    memberships.set(photo.id, new Set(seed?.memberships?.[photo.id] ?? []));
  }

  return {
    async listAlbums() {
      return [...albums];
    },

    async listPhotos() {
      return [...photos];
    },

    async createAlbum(title) {
      albumCounter += 1;
      const album = { id: `album-${albumCounter}`, title };
      albums.push(album);
      return album;
    },

    async renameAlbum(albumId, title) {
      const album = albums.find((item) => item.id === albumId);
      if (!album) {
        throw new Error('Album not found.');
      }
      album.title = title;
      return { ...album };
    },

    async addPhotoToAlbum(albumId, photoId) {
      const set = memberships.get(photoId) ?? new Set<string>();
      set.add(albumId);
      memberships.set(photoId, set);
    },

    async removePhotoFromAlbum(albumId, photoId) {
      memberships.get(photoId)?.delete(albumId);
    },

    async isPhotoInAlbum(albumId, photoId) {
      return memberships.get(photoId)?.has(albumId) ?? false;
    },
  };
}

