    google?: {
      accounts: {
        oauth2: {
          initTokenClient(config: {
            client_id: string;
            scope: string;
            callback: (response: { access_token?: string; error?: string }) => void;
          }): { requestAccessToken: () => void };
        };
      };
    };
  }
}

export type AuthAdapter = {
  signIn(): Promise<string>;
};

let scriptPromise: Promise<void> | null = null;

function loadGoogleAccountsScript(): Promise<void> {
  if (window.google?.accounts?.oauth2) {
    return Promise.resolve();
  }

  if (scriptPromise) {
    return scriptPromise;
  }

  scriptPromise = new Promise<void>((resolve, reject) => {
    const script = document.createElement('script');
    script.src = GOOGLE_ACCOUNTS_SCRIPT;
    script.async = true;
    script.defer = true;
    script.onload = () => resolve();
    script.onerror = () => reject(new Error('Unable to load Google Identity Services.'));
    document.head.appendChild(script);
  });

  return scriptPromise;
}

export function createGoogleAuthAdapter(clientId: string | undefined): AuthAdapter {
  return {
    async signIn() {
      if (!clientId) {
        throw new Error('Set VITE_GOOGLE_CLIENT_ID before signing in.');
      }

      await loadGoogleAccountsScript();

      return new Promise<string>((resolve, reject) => {
        const tokenClient = window.google?.accounts.oauth2.initTokenClient({
          client_id: clientId,
          scope: SCOPES,
          callback: (response) => {
            if (response.error || !response.access_token) {
              reject(new Error(response.error ?? 'Google sign-in failed.'));
              return;
            }
            resolve(response.access_token);
          },
        });

        if (!tokenClient) {
          reject(new Error('Google Identity Services is unavailable.'));
          return;
        }

        tokenClient.requestAccessToken();
      });
    },
  };
}

