    { id: 'older', title: 'older.jpg', previewUrl: 'https://example.com/older.jpg', timestamp: '2024-01-01' },
  ];
  index = 0;
  memberships = new Map<string, Set<string>>([
    ['newer', new Set(['family'])],
    ['older', new Set(['office'])],
  ]);

  async isSignedIn() {
    return this.signedIn;
  }

