    }

    const nextX = Math.max(0, Math.min(event.clientX - this.dragState.offsetX, this.windowRef.innerWidth - 72));
    const nextY = Math.max(0, Math.min(event.clientY - this.dragState.offsetY, this.windowRef.innerHeight - 72));
